// modules/teams/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'teams',
  description: 'Handles team creation, management, and membership utilities.',

  dependencies: { modules: ['auth'] },

  exposes: {
    routes: [
      { method: 'POST', path: '/teams/create', auth: true },
    ],
    functions: ['createTeam'],
    types: ['Team', 'TeamMember', 'TeamError'],
  },

  sideEffects: [
    'writes to: teams table',
    'writes to: team_members table',
  ],

  invariants: [
    'A team must always have at least one owner',
    'Only the owner can create a new team',
    'New members must be added to the team_members table',
  ],
});

